#include <vector>
#include <queue>
#include <climits>
#include <utility>
#include <unordered_map>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build the graph: original edges and reversed edges (for possible switches)
    unordered_map<long long, vector<pair<long long, long long>>> graph;
    unordered_map<long long, vector<pair<long long, long long>>> reversed_edges;

    for (const auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        graph[u].emplace_back(v, w);
        reversed_edges[v].emplace_back(u, w);
    }

    // Dijkstra's algorithm with state (node, whether switch is used)
    // dist[node][0] = distance to node without using switch
    // dist[node][1] = distance to node after using switch
    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    dist[0][0] = 0;

    // Priority queue: (distance, node, switch_used)
    priority_queue<tuple<long long, long long, bool>, 
                   vector<tuple<long long, long long, bool>>, 
                   greater<tuple<long long, long long, bool>>> pq;
    pq.emplace(0, 0, false);

    while (!pq.empty()) {
        auto [current_dist, u, used_switch] = pq.top();
        pq.pop();

        if (current_dist > dist[u][used_switch]) {
            continue;
        }

        // Explore normal edges
        for (const auto& [v, w] : graph[u]) {
            if (current_dist + w < dist[v][used_switch]) {
                dist[v][used_switch] = current_dist + w;
                pq.emplace(dist[v][used_switch], v, used_switch);
            }
        }

        // If switch hasn't been used yet, explore reversed edges
        if (!used_switch) {
            for (const auto& [v, w] : reversed_edges[u]) {
                long long new_dist = current_dist + 2 * w;
                if (new_dist < dist[v][true]) {
                    dist[v][true] = new_dist;
                    pq.emplace(new_dist, v, true);
                }
            }
        }
    }

    long long result = min(dist[n-1][0], dist[n-1][1]);
    return result == LLONG_MAX ? -1 : result;
}

