function solve(n, edges) {
    // Build the graph: original edges and reversed edges (for possible switches)
    const graph = new Map();
    const reversedEdges = new Map();

    for (const [u, v, w] of edges) {
        if (!graph.has(u)) graph.set(u, []);
        graph.get(u).push([v, w]);

        if (!reversedEdges.has(v)) reversedEdges.set(v, []);
        reversedEdges.get(v).push([u, w]);
    }

    // Dijkstra's algorithm with state (node, whether switch is used)
    // dist[node][0] = distance to node without using switch
    // dist[node][1] = distance to node after using switch
    const dist = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] = 0;

    // Priority queue: [distance, node, switchUsed]
    const pq = new MinPriorityQueue({
        priority: ([d]) => d
    });
    pq.enqueue([0, 0, false]);

    while (!pq.isEmpty()) {
        const { element: [currentDist, u, usedSwitch] } = pq.dequeue();

        if (currentDist > dist[u][usedSwitch ? 1 : 0]) {
            continue;
        }

        // Explore normal edges
        if (graph.has(u)) {
            for (const [v, w] of graph.get(u)) {
                const newDist = currentDist + w;
                if (newDist < dist[v][usedSwitch ? 1 : 0]) {
                    dist[v][usedSwitch ? 1 : 0] = newDist;
                    pq.enqueue([newDist, v, usedSwitch]);
                }
            }
        }

        // If switch hasn't been used yet, explore reversed edges
        if (!usedSwitch && reversedEdges.has(u)) {
            for (const [v, w] of reversedEdges.get(u)) {
                const newDist = currentDist + 2 * w;
                if (newDist < dist[v][1]) {
                    dist[v][1] = newDist;
                    pq.enqueue([newDist, v, true]);
                }
            }
        }
    }

    const result = Math.min(dist[n-1][0], dist[n-1][1]);
    return result === Infinity ? -1 : result;
}

// MinPriorityQueue implementation using a simple array and sort (for simplicity)
class MinPriorityQueue {
    constructor({ priority }) {
        this.queue = [];
        this.priority = priority;
    }

    enqueue(element) {
        this.queue.push(element);
        this.queue.sort((a, b) => this.priority(a) - this.priority(b));
    }

    dequeue() {
        return { element: this.queue.shift() };
    }

    isEmpty() {
        return this.queue.length === 0;
    }
}
